```csharp
class Person
{
    private int _age;

    public int Age
    {
        get => _age;
        set => _age = value;
    }
}

var p = new Person();
p.Age = 25;              // set
Console.WriteLine(p.Age); // get → 25
```

```csharp
class Animal { public string Name; }

class Dog : Animal  // Dog inherits from Animal
{
    public void Bark() { Console.WriteLine("Woof!"); }
}

var dog = new Dog { Name = "Rex" }; // Name comes from Animal
```

```csharp
class Animal
{
    public virtual string Sound() { return "..."; }
}

class Dog : Animal
{
    public override string Sound() { return "Woof!"; }
}

Animal a = new Dog();
Console.WriteLine(a.Sound()); // Woof!
```

```csharp
abstract class Shape
{
    public abstract double Area(); // no body — must be implemented
}

class Circle : Shape
{
    double r;
    public Circle(double r) { this.r = r; }
    public override double Area() { return Math.PI * r * r; }
}
```

```csharp
interface IShape
{
    double Area();
}

class Square : IShape
{
    double side;
    public Square(double s) { side = s; }
    public double Area() { return side * side; }
}
```

